function countKeys(obj: any): number {
  let count = 0;
  for (const key of Object.keys(obj)) {
    if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key])) {
      count += countKeys(obj[key]);
    } else {
      count++;
    }
  }
  return count;
}

describe('Apply portfolio translations', () => {
  const files = [
    { name: 'zh.json', translations: ZH_PORTFOLIO },
    { name: 'hi.json', translations: HI_PORTFOLIO },
    { name: 'bn.json', translations: BN_PORTFOLIO },
  ];

  for (const { name, translations } of files) {
    it(`should apply portfolio translations to ${name}`, () => {
      const filePath = path.resolve(__dirname, `../i18n/locales/${name}`);
      const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
      data.portfolio = translations;
      fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n', 'utf-8');
      const keyCount = countKeys(translations);
      console.log(`${name}: Applied ${keyCount} translated keys in portfolio section`);
      expect(keyCount).toBeGreaterThan(300);
    });
  }
});
